        { id: "d4q4", pergunta: "Segundo 2 Coríntios 5:20, como Paulo se descreve, em nome de Cristo?", opcoes: ["Como juiz", "Como embaixador de Cristo", "Como rei", "Como escravo sem função"], correta: 1, explicacao: "A resposta correta é: Como embaixador de Cristo." }
