      perguntas: [
        { id: "d5q1", pergunta: "Segundo o texto, quantos apelos à santidade Paulo faz em 2 Coríntios 6:14-7:1?", opcoes: ["Três", "Seis", "Dez", "Nenhum"], correta: 1, explicacao: "A resposta correta é: Seis." },
        { id: "d5q2", pergunta: "Segundo o texto, quantas promessas de Deus acompanham o chamado à santidade?", opcoes: ["Duas", "Sete", "Uma", "Doze"], correta: 1, explicacao: "A resposta correta é: Sete." },
        { id: "d5q3", pergunta: "Segundo o texto, a santidade é resultado de quê?", opcoes: ["Apenas do esforço humano", "Da obra do Espírito Santo no coração, embora os crentes também façam sua parte", "De rituais externos apenas", "Da riqueza material"], correta: 1, explicacao: "A resposta correta é: Da obra do Espírito Santo no coração, embora os crentes também façam sua parte." },
        { id: "d5q4", pergunta: "Segundo 2 Coríntios 6:14, o que os crentes não devem fazer?", opcoes: ["Orar em público", "Pôr-se em jugo desigual com os incrédulos", "Estudar as Escrituras", "Compartilhar o evangelho"], correta: 1, explicacao: "A resposta correta é: Pôr-se em jugo desigual com os incrédulos." }
      ]
