        { id: "d7q2", pergunta: "Segundo Ellen White, citando 1 João 4:16, o que é a natureza e a lei de Deus?", opcoes: ["Julgamento", "Amor", "Poder apenas", "Distância"], correta: 1, explicacao: "A resposta correta é: Amor." },
        { id: "d7q3", pergunta: "Segundo Ellen White, o Espírito Santo tem personalidade?", opcoes: ["Não, é apenas uma força", "Sim, Ele tem uma personalidade", "O texto não aborda isso", "Apenas ocasionalmente"], correta: 1, explicacao: "A resposta correta é: Sim, Ele tem uma personalidade." },
        { id: "d7q4", pergunta: "Segundo Ellen White, em nome de quantas pessoas vivas na Trindade celestial os cristãos são batizados?", opcoes: ["Uma", "Três: o Pai, o Filho e o Espírito Santo", "Duas", "Nenhuma, o batismo não menciona a Trindade"], correta: 1, explicacao: "A resposta correta é: Três: o Pai, o Filho e o Espírito Santo." }
